import { parseIsnbFrame, isnbToPlatformData } from './src/utils/isnb.parser';

// 示例1：参数上报（水压配置信息）
const hex1 = '';

// 示例2：定时上报（水压+电量）
const hex2 = '';

// 示例3：告警（水压故障+电量）
const hex3 = '';

// 示例4：心跳（水压故障+电量）
const hex4 = '';

function printResult(label: string, hex: string) {
  console.log(`\n========== ${label} ==========`);
  const frame = parseIsnbFrame(hex);
  if (!frame) {
    console.log('解析失败');
    return;
  }
  console.log('messageId:', frame.messageId);
  console.log('messageTypeName:', frame.messageTypeName);
  console.log('devType:', frame.devType);
  console.log('devTypeName:', frame.devTypeName);
  console.log('imei:', frame.imei);
  console.log('deviceModel:', frame.deviceModel);
  console.log('channelCount:', frame.channelCount);
  console.log('channels:');
  for (const ch of frame.channels) {
    console.log(`  channelNo=${ch.channelNo}, paramTypeName=${ch.paramTypeName}, paramValue=${ch.paramValue}${ch.paramUnit ? ' ' + ch.paramUnit : ''}, eventTypeName=${ch.eventTypeName}, eventValue=${ch.eventValue}`);
  }
  console.log('hasAlarm:', frame.hasAlarm);
  console.log('hasFault:', frame.hasFault);
  const data = isnbToPlatformData(frame);
  console.log('platformData keys:', Object.keys(data).join(', '));
}

printResult('示例1：参数上报（水压配置信息）', hex1);
printResult('示例2：定时上报（水压+电量）', hex2);
printResult('示例3：告警（水压故障+电量）', hex3);
printResult('示例4：心跳（水压故障+电量）', hex4);

console.log('\n========== 所有示例验证完成 ==========');
